#include <bits/stdc++.h>
#define int long long
#define mk make_pair
#define PII pair<int,int>
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a : b)
#define wh while
#define inf 0x3f3f3f3f3f3f3f3f
#define IOS ios::sync_with_stdio(false);cin.tie(0);cout.tie(0);
#define snd second
#define fst first
#define pb push_back
#define CI const int
#define NP namespace
using NP std;
int quickpow(int a,int b)
{
	int ans=1;
	wh(b)
	{
		if(b&1)ans=ans*a;
        a=a*a;
		b>>=1;
	}
	return ans;
}
CI MOD=1e9+7,MAXN=9e3+5;
int k,m,dp[1005][MAXN],l;
string s;
int f(int x)
{
    int ans=0;
    while(x)
    {
        ans+=x%10;
        x/=10;
    }
    return ans;
}
bool check(int x)
{
	FOR(i,1,k)x=f(x);
	if(x==m)return true;
	return false;
}
void DP()
{
	int sum=s[0]-'0';
	memset(dp,0,sizeof dp);
	FOR(i,0,s[0]-'0'-1)
	{
		dp[0][i]=1;
	}
	FOR(i,1,l-1)
	{
		FOR(j,0,9*(i+1))
		{
			if(j-sum<s[i]-'0'&&j-sum>=0)
			{
				++dp[i][j];
			}
			FOR(d,0,9)
			{
				if(d>j)
				{
					break;
				}
				dp[i][j]=(dp[i][j]+dp[i-1][j-d])%MOD;
			}
		}
		sum+=s[i]-'0';
	}
	++dp[l-1][sum];
}
void solve()
{
    cin>>s>>k>>m;
    k=min(k,4ll)-1;
    l=s.size();
	DP();
	int ans=0;
	FOR(i,1,9000)
	{
		if(check(i))
		{
			ans=(ans+dp[l-1][i])%MOD;
		}
	}
	cout<<ans<<'\n';
}
signed main()
{
	// freopen("game.in","r",stdin);
	// freopen("game.out","w",stdout);
	IOS
    int T;
	cin>>T;
	wh(T--)
	{
    	solve();
	}
	return false;
}
